import{c as r,a7 as l,y as i,B as t}from"./chunks/framework.3cjvm90C.js";const p=JSON.parse('{"title":"拒绝采样在 RLHF 中的应用","description":"介绍拒绝采样方法在强化学习人类反馈中的原理与实践应用","frontmatter":{"title":"拒绝采样在 RLHF 中的应用","description":"介绍拒绝采样方法在强化学习人类反馈中的原理与实践应用"},"headers":[],"relativePath":"rlhf/paper/reject_sampling.md","filePath":"rlhf/paper/reject_sampling.md","lastUpdated":1782448598000}'),e={name:"rlhf/paper/reject_sampling.md"};function n(o,a,s,h,g,_){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="拒绝采样-reject-sampling-在-rlhf-中的应用" tabindex="-1">拒绝采样（Reject Sampling）在 RLHF 中的应用 <a class="header-anchor" href="#拒绝采样-reject-sampling-在-rlhf-中的应用" aria-label="Permalink to “拒绝采样（Reject Sampling）在 RLHF 中的应用”">​</a></h1><h2 id="_1-拒绝采样的核心思想" tabindex="-1"><strong>1. 拒绝采样的核心思想</strong> <a class="header-anchor" href="#_1-拒绝采样的核心思想" aria-label="Permalink to “1. 拒绝采样的核心思想”">​</a></h2><p>拒绝采样是一种从复杂分布中生成样本的技术，通过以下步骤实现：</p><ol><li><strong>生成候选样本</strong>：使用一个易于采样的<strong>提议分布</strong>生成候选样本。</li><li><strong>评估样本质量</strong>：根据目标分布的概率密度函数（或替代评估标准）计算每个样本的<strong>接受概率</strong>。</li><li><strong>接受或拒绝样本</strong>：以一定概率接受样本，否则拒绝。</li></ol><p>在 RL 场景中，目标是从当前策略（Checkpoint）生成的样本中筛选出高质量数据，用于监督式微调。</p><h2 id="_2-在-rl-中应用拒绝采样的具体流程" tabindex="-1"><strong>2. 在 RL 中应用拒绝采样的具体流程</strong> <a class="header-anchor" href="#_2-在-rl-中应用拒绝采样的具体流程" aria-label="Permalink to “2. 在 RL 中应用拒绝采样的具体流程”">​</a></h2><h3 id="步骤-1-生成候选样本" tabindex="-1"><strong>步骤 1：生成候选样本</strong> <a class="header-anchor" href="#步骤-1-生成候选样本" aria-label="Permalink to “步骤 1：生成候选样本”">​</a></h3><ul><li>使用当前 RL 策略（Checkpoint）对一批输入（例如用户查询）生成多个候选响应。</li><li>例如，对于每个输入 $ q $，策略 $ \\pi_{\\theta} $ 生成 $ N $ 个响应 $ { o_1, o_2, ..., o_N } $。</li></ul><h3 id="步骤-2-评估样本质量" tabindex="-1"><strong>步骤 2：评估样本质量</strong> <a class="header-anchor" href="#步骤-2-评估样本质量" aria-label="Permalink to “步骤 2：评估样本质量”">​</a></h3><ul><li>通过<strong>奖励模型（Reward Model）</strong>或<strong>人工标注</strong>对每个候选响应打分，得到奖励值 $ r_i $。</li><li>奖励值可能基于： <ul><li>响应与期望答案的匹配度（如 BLEU、ROUGE）。</li><li>人类偏好（如安全性、连贯性）。</li><li>任务相关的性能指标（如代码正确性、数学解题步骤）。</li></ul></li></ul><h3 id="步骤-3-计算接受概率" tabindex="-1"><strong>步骤 3：计算接受概率</strong> <a class="header-anchor" href="#步骤-3-计算接受概率" aria-label="Permalink to “步骤 3：计算接受概率”">​</a></h3><ul><li>对每个候选响应 $ o_i $，计算接受概率 $ \\alpha_i $： $$ \\alpha_i = \\frac{r_i}{\\max(r_1, r_2, ..., r_N)} \\quad \\text{或} \\quad \\alpha_i = \\text{sigmoid}(r_i - \\tau) $$ 其中 $ \\tau $ 为阈值，用于控制筛选严格度。</li></ul><h3 id="步骤-4-接受或拒绝样本" tabindex="-1"><strong>步骤 4：接受或拒绝样本</strong> <a class="header-anchor" href="#步骤-4-接受或拒绝样本" aria-label="Permalink to “步骤 4：接受或拒绝样本”">​</a></h3><ul><li>对每个候选响应，以概率 $ \\alpha_i $ 接受该样本，否则拒绝。</li><li>最终保留的样本构成新的 SFT 数据集 $ \\mathcal{D}_{\\text{SFT} } $。</li></ul><h3 id="步骤-5-监督式微调-sft" tabindex="-1"><strong>步骤 5：监督式微调（SFT）</strong> <a class="header-anchor" href="#步骤-5-监督式微调-sft" aria-label="Permalink to “步骤 5：监督式微调（SFT）”">​</a></h3><ul><li>使用 $ \\mathcal{D}_{\\text{SFT} } $ 对模型进行微调，提升其在特定任务上的表现。</li></ul><hr><h2 id="_3-拒绝采样的优势" tabindex="-1"><strong>3. 拒绝采样的优势</strong> <a class="header-anchor" href="#_3-拒绝采样的优势" aria-label="Permalink to “3. 拒绝采样的优势”">​</a></h2><ol><li><strong>数据质量提升</strong>：通过筛选高奖励样本，避免低质量数据污染训练集。</li><li><strong>稳定性增强</strong>：在 RL 接近收敛时，策略生成的样本趋于稳定，拒绝采样可进一步优化数据分布。</li><li><strong>效率优化</strong>：仅保留有价值样本，减少冗余计算。</li></ol><hr><h2 id="_4-实际应用案例" tabindex="-1"><strong>4. 实际应用案例</strong> <a class="header-anchor" href="#_4-实际应用案例" aria-label="Permalink to “4. 实际应用案例”">​</a></h2><ul><li><strong>PPO （Proximal Policy Optimization）</strong>：在策略更新时，通过重要性采样和裁剪（Clipping）隐式实现拒绝采样。</li><li><strong>GRPO （Group Relative Policy Optimization）</strong>：使用分组评估奖励，动态调整接受阈值。</li><li><strong>AlphaZero</strong>：在蒙特卡洛树搜索（MCTS）中，通过价值网络筛选高价值路径。</li></ul><hr><h2 id="_5-数学示例" tabindex="-1"><strong>5. 数学示例</strong> <a class="header-anchor" href="#_5-数学示例" aria-label="Permalink to “5. 数学示例”">​</a></h2><p>假设当前策略 $ \\pi_{\\theta} $ 生成三个候选响应，奖励分别为 $ r_1=0.8, r_2=0.5, r_3=0.9 $：</p><ol><li><strong>归一化接受概率</strong>：$ \\alpha_1 = 0.8/0.9 \\approx 0.89 $, $ \\alpha_2 = 0.5/0.9 \\approx 0.56 $, $ \\alpha_3 = 1 $。</li><li><strong>按概率接受</strong>：响应 3 必然被接受，响应 1 以 89% 概率接受，响应 2 以 56% 概率接受。</li><li>最终可能保留响应 1 和 3，加入 SFT 数据集。</li></ol><hr><h2 id="_6-注意事项" tabindex="-1"><strong>6. 注意事项</strong> <a class="header-anchor" href="#_6-注意事项" aria-label="Permalink to “6. 注意事项”">​</a></h2><ul><li><strong>奖励模型的偏差</strong>：若奖励模型与真实目标不一致，可能导致筛选偏差。</li><li><strong>多样性损失</strong>：过度筛选可能减少数据多样性，需平衡质量与覆盖度。</li><li><strong>计算开销</strong>：生成和评估大量候选样本会增加训练成本。</li></ul>',29)])])}const c=r(e,[["render",n]]);export{p as __pageData,c as default};
